import React, {type FunctionComponent, type JSX, useCallback, useContext, useRef, useState,} from "react";
import {Container, Button, Flex} from "../../_compat";
import {handleDownload} from "../helpers";
import {WidgetsContext} from "../context";
import {BsExclamationCircle} from "react-icons/bs";
import type {IUseFormReturn} from "@lmb-it/kitsconcerto-types";
import {useDisclosure, useLanguage} from "../../hooks";

import {BiDownload} from "react-icons/bi";
import {useUpdateEffect} from "primereact/hooks";

const ChartContainer: FunctionComponent<{ children?: JSX.Element }> = ({
                                                                           children,
                                                                       }) => {
    const {
        enableExportButton = true,
        data: {stats, datasets},
        id = Math.random().toString(16).slice(2),
        label,
        info,
        isDarkMode = false,
        containerProps,
        height = 300,
        aspectRatio: _ = 1.5,
    } = useContext(WidgetsContext);

    const {t} = useLanguage();
    const {isOpen, onOpen, onClose} = useDisclosure();
    const isFirstRun = useRef<boolean>(true);


    const [mainFormData, setMainFormData] = useState<IUseFormReturn | null>(null);
    const formDataRef = useCallback(
        (form: IUseFormReturn) => setMainFormData(form),
        [],
    );

    useUpdateEffect(() => {
        const notEmptyDataSets =
            !!datasets &&
            Object.entries(datasets.fixedOptions).every(([key, value]) => !!value);

        if (!!mainFormData && notEmptyDataSets && isFirstRun.current) {
            mainFormData.setValues(datasets.fixedOptions);
            isFirstRun.current = false;
        }
    }, [datasets, !!mainFormData]);

    const chart = useRef(undefined);

    const withStatistics = stats && stats.length > 0;
    return (
        <Container
            title={label}
            rightElement={
                <Flex gap={3} justifyContent={"space-between"}>
                    {!!info && (
                        <Button
                            tooltip={info}
                            size={"sm"}
                            severity={"secondary"}
                            aria-label={info}
                            icon={<BsExclamationCircle/>}
                        />
                    )}

                    {enableExportButton && (
                        <Button
                            tooltip={t("generatePhoto")}
                            size={"sm"}
                            severity={"secondary"}
                            aria-label={t("settings")}
                            icon={<BiDownload/>}
                            onClick={() => handleDownload(id, chart, isDarkMode)}
                        />
                    )}
                </Flex>
            }
            w={"full"}
            h={"full"}
            {...containerProps}
        >
            <Flex flexDirection={"column"} w={"full"} h={"full"}>
                <Flex
                    w={"100%"}
                    h={height ?? "100%"}
                    gap={2}
                    flexDirection={"row"}
                    justifyContent={"center"}
                >
                    <Flex flex={1} h={"full"}>
                        {children}
                    </Flex>
                    {/* {withStatistics && (
            <Flex flex={1}>
              <Statistics stats={stats} />
            </Flex>
          )}*/}
                </Flex>
            </Flex>
        </Container>
    );
};

export default ChartContainer;
